import{_ as a,o,c,ag as i}from"./chunks/framework.DTiDeF2Q.js";const u=JSON.parse('{"title":"Аліаси архівів | Dotfiles (UK)","titleTemplate":":title","description":"Короткі команди архівування. Огляд для Dotfiles v0.2.495. Сумісно з macOS, Linux та WSL через Dotfiles.","frontmatter":{"title":"Аліаси архівів | Dotfiles","description":"Короткі команди архівування. Огляд для Dotfiles v0.2.495. Сумісно з macOS, Linux та WSL через Dotfiles.","lang":"uk-UA","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Аліаси архівів | Dotfiles preview","canonical":"/uk/aliases/archives/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Аліаси архівів","pageType":"docs","schemaType":"WebPage","permalink":"/uk/aliases/archives/"},"headers":[],"relativePath":"uk/aliases/archives/index.md","filePath":"uk/aliases/archives/index.md","lastUpdated":1773010926000}'),l={name:"uk/aliases/archives/index.md"};function t(d,e,r,s,n,p){return o(),c("div",null,[...e[0]||(e[0]=[i('<h1 id="аліаси-архівів" tabindex="-1">Аліаси архівів <a class="header-anchor" href="#аліаси-архівів" aria-label="Permalink to &quot;Аліаси архівів&quot;">​</a></h1><p>Короткі імена команд архівування.</p><p>Ця сторінка знайомить з однією групою аліасів та її поширеними скороченнями команд. Прочитайте її спочатку, щоб зрозуміти угоди про іменування, очікувані вхідні дані та безпечні шаблони виконання. Потім відкрийте довідковий додаток для повного переліку команд та точного синтаксису. Ці аліаси зменшують повторний набір та зберігають послідовну поведінку робочого процесу на macOS, Linux та WSL.</p><h2 id="коли-використовувати" tabindex="-1">Коли використовувати <a class="header-anchor" href="#коли-використовувати" aria-label="Permalink to &quot;Коли використовувати&quot;">​</a></h2><p>Використовуйте цю сторінку перед щоденною роботою в оболонці, коли вам потрібні передбачувані шаблони команд.</p><h2 id="що-включено" tabindex="-1">Що включено <a class="header-anchor" href="#що-включено" aria-label="Permalink to &quot;Що включено&quot;">​</a></h2><ul><li>Аліаси: 40</li><li>Допоміжні функції: 3</li><li>Файли джерел: 1</li></ul><h2 id="швидкі-приклади" tabindex="-1">Швидкі приклади <a class="header-anchor" href="#швидкі-приклади" aria-label="Permalink to &quot;Швидкі приклади&quot;">​</a></h2><ul><li><code>ac</code> → <code>&#39;compress&#39; # Загальне стиснення (Archive Create)</code></li><li><code>acl</code> → <code>&#39;compress_large&#39; # Застаріле compress_large</code></li><li><code>bak</code> → <code>&#39;backup&#39; # Швидке резервне копіювання</code></li><li><code>c7z</code> → <code>&#39;7z a&#39; # Створити архів 7z</code></li><li><code>cbz</code> → <code>&#39;bzip2 -zk&#39; # Стиснути з bzip2</code></li><li><code>cgz</code> → <code>&#39;gzip -cv&#39; # Стиснути з gzip</code></li><li><code>clz4</code> → <code>&#39;lz4 -zc&#39; # Стиснути з lz4</code></li><li><code>crar</code> → <code>&#39;rar a&#39; # Створити архів rar</code></li><li><code>ctar</code> → <code>&#39;tar -cvf&#39; # Створити архів tar</code></li><li><code>ctbz</code> → <code>&#39;tar -jcvf&#39; # Створити архів tar.bz2</code></li><li><code>ctgz</code> → <code>&#39;tar -zcvf&#39; # Створити архів tar.gz</code></li><li><code>ctxz</code> → <code>&#39;tar -Jcvf&#39; # Створити архів tar.xz</code></li></ul><h2 id="наступнии-крок" tabindex="-1">Наступний крок <a class="header-anchor" href="#наступнии-крок" aria-label="Permalink to &quot;Наступний крок&quot;">​</a></h2><p>Відкрити повний перелік:</p>',11)])])}const f=a(l,[["render",t]]);export{u as __pageData,f as default};
